E = int(input())
D = int(input())

if E > D:
    print(E + D)
else:
    print(2 * (D - E))

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    N = int(input_data[0])
    Q = int(input_data[1])

    grid = []
    for i in range(N):
        grid.append([int(c) for c in input_data[2 + i]])

    for _ in range(Q):
        new_grid = [[0 for _ in range(N)] for _ in range(N)]
        for r in range(N):
            for c in range(N):
                live_neighbors = 0
                for dr in [-1, 0, 1]:
                    for dc in [-1, 0, 1]:
                        if dr == 0 and dc == 0:
                            continue
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < N and 0 <= nc < N:
                            if grid[nr][nc] == 1:
                                live_neighbors += 1

                if grid[r][c] == 1:
                    if live_neighbors == 2 or live_neighbors == 3:
                        new_grid[r][c] = 1
                    else:
                        new_grid[r][c] = 0
                else:
                    if live_neighbors == 3:
                        new_grid[r][c] = 1
                    else:
                        new_grid[r][c] = 0
        grid = new_grid

    for row in grid:
        print("".join(map(str, row)))

if __name__ == "__main__":
    solve()

import sys

def solve():
    try:
        line1 = sys.stdin.readline().split()
        if not line1:
            return
        k, n = map(int, line1)

        alphabet_str = sys.stdin.readline().strip('\n\r')
        message_str = sys.stdin.readline().strip('\n\r')

        alphabet_set = set(alphabet_str)

        possible = True
        for char in message_str:
            if char not in alphabet_set:
                possible = False
                break

        if possible:
            print('S')
        else:
            print('N')
    except EOFError:
        pass

if __name__ == "__main__":
    solve()
